#include <stdio.h>
#include <stdlib.h>
int main() {
    int w, h, d, n;
    scanf("%d %d %d %d", &w, &h, &d, &n);
    int **barricades = (int **)malloc(n * sizeof(int *));
    for (int i = 0; i < n; i++) {
        barricades[i] = (int *)malloc(3 * sizeof(int));
        scanf("%d %d %d", &barricades[i][0], &barricades[i][1], &barricades[i][2]);
    }
    int minCost = 1000000000;
    for (int x = d; x <= w - d; x++) {
        for (int y = d; y <= h - d; y++) {
            int cost = 0;
            for (int i = 0; i < n; i++) {
                if (abs(barricades[i][0] - x) <= d && abs(barricades[i][1] - y) <= d) {
                    cost += barricades[i][2];
                }
            }
            if (cost < minCost) {
                minCost = cost;
            }
        }
    }
    printf("%d\n", minCost);
    return 0;
}

