            barricades[i][1] = scanner.nextInt();
            barricades[i][2] = scanner.nextInt();
        }
        int minCost = 1000000000;
        for (int x = d; x <= w - d; x++) {
            for (int y = d; y <= h - d; y++) {
                int cost = 0;
                for (int i = 0; i < n; i++) {
                    if (Math.abs(barricades[i][0] - x) <= d && Math.abs(barricades[i][1] - y) <= d) {
